1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty array for two adjacent live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    expect(nextGeneration([[1, 0], [1, 1], [1, 2]])).toContainEqual([1, 1]);
16	  });
17	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
18	    expect(nextGeneration([[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]])).not.toContainEqual([1, 1]);
19	  });
20	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
21	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
22	  });
23	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
24	  it.todo("should keep a 2x2 block unchanged (still life)");
25	});
