1	type Cell = [number, number];
2	
3	const key = (x: number, y: number): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const neighbors: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      neighbors.push([x + dx, y + dy]);
11	    }
12	  }
13	  return neighbors;
14	};
15	
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  const liveSet = new Set<string>(cells.map(([x, y]) => key(x, y)));
18	  const isAlive = (cell: Cell): boolean => liveSet.has(key(cell[0], cell[1]));
19	  const liveNeighborCount = (cell: Cell): number =>
20	    neighborsOf(cell).filter(isAlive).length;
21	
22	  const survivors = cells.filter((cell) => {
23	    const count = liveNeighborCount(cell);
24	    return count === 2 || count === 3;
25	  });
26	
27	  const deadNeighborKeys = new Set<string>();
28	  const deadNeighbors: Cell[] = [];
29	  for (const cell of cells) {
30	    for (const neighbor of neighborsOf(cell)) {
31	      const neighborKey = key(neighbor[0], neighbor[1]);
32	      if (!liveSet.has(neighborKey) && !deadNeighborKeys.has(neighborKey)) {
33	        deadNeighborKeys.add(neighborKey);
34	        deadNeighbors.push(neighbor);
35	      }
36	    }
37	  }
38	
39	  const births = deadNeighbors.filter((cell) => liveNeighborCount(cell) === 3);
40	
41	  return [...survivors, ...births];
42	}
